mapper.select:
SELECT r.REPORT_ID AS reportId , r.TARGET_CODE AS targetCode , r.TARGET_ID AS targetId , r.REPORTER_EMAIL AS reporterEmail , r.REASON_CODE AS reasonCode , r.DETAIL AS detail , r.REPORT_STATUS_CODE AS reportStatusCode , r.PROCESSED_BY AS processedBy , r.CREATED_AT AS createdAt , r.PROCESSED_AT AS processedAt FROM reports r WHERE 1=1
AND r.REPORT_ID < #{lastId}
ORDER BY r.REPORT_ID DESC LIMIT #{size}
